<template lang="pug">
.mi
  img(:src="avatar" alt="avatar")
  p Misha /mioe Gezha
  span {{ desc }}
</template>


<script>
export default {
  name: 'WelcomeMi',
  asyncData() {
    return {
      avatar: null,
      desc: null,
    }
  },

  created() {
    this.avatar = this.getAvatar()
    this.desc = this.getDescription()
  },

  methods: {
    getRandom(min, max) {
      // https://developer.mozilla.org/ru/docs/Web/JavaScript/Reference/Global_Objects/Math/random
      return Math.floor(Math.random() * (max - min) + min) // максимум не включается, минимум включается
    },

    getAvatar() {
      const folder = 'images/mi'
      const img = [
        `${folder}/mioe.png`,
        `${folder}/photo15082013.jpg`,
        `${folder}/photo14072014.jpg`,
        `${folder}/photo14122018.jpg`,
      ]
      const r = this.getRandom(0, img.length)
      return img[r]
    },

    getDescription() {
      const desc = [
        'typical developer 👨‍💻',
        'black magician 🧙‍',
        'hater of a semicolon 😾',
      ]
      const r = this.getRandom(0, desc.length)
      return desc[r]
    },
  },
}
</script>


