<template lang="pug">
canvas(ref="bubbles")
</template>


<script>
import { randomNormal, rand } from './helpers'

const CONFIG = {
  BUBBLES_COUNT: 600,
  BUBBLES_SIZE: 0.5,
  BUBBLES_SPEED: 20000,
}

let bubbles = []

export default {
  name: 'Bubbles',

  mounted() {
    this.start()
  },

  methods: {
    start() {
      const [canvas, ctx] = this.init()
      for (let i = 0; i < CONFIG.BUBBLES_COUNT; i++) {
        bubbles.push(this.createBubble())
      }
      requestAnimationFrame((time) => this.draw(time, canvas, ctx))
    },

    init() {
      let canvas = this.$refs['bubbles']
      canvas.width = canvas.offsetWidth * window.devicePixelRatio
      canvas.height = canvas.offsetHeight * window.devicePixelRatio
      let ctx = canvas.getContext("2d")

      window.addEventListener('resize', () => {
        canvas.width = canvas.offsetWidth * window.devicePixelRatio
        canvas.height = canvas.offsetHeight * window.devicePixelRatio
        ctx = canvas.getContext("2d")
      })

      return [canvas, ctx]
    },

    createBubble() {
      const colour = {
        r: 255,
        g: randomNormal({ mean: 125, dev: 20 }),
        b: 50,
        a: rand(0, 1),
      }
      return {
        x: -2,
        y: -2,
        diameter: Math.max(0, randomNormal({ mean: CONFIG.BUBBLES_SIZE, dev: CONFIG.BUBBLES_SIZE / 2 })),
        duration: randomNormal({ mean: CONFIG.BUBBLES_SPEED, dev: CONFIG.BUBBLES_SPEED * 0.1 }),
        amplitude: randomNormal({ mean: 16, dev: 2 }),
        offsetY: randomNormal({ mean: 0, dev: 10 }),
        arc: Math.PI * 2,
        startTime: performance.now() - rand(0, CONFIG.BUBBLES_SPEED),
        colour: `rgba(${colour.r}, ${colour.g}, ${colour.b}, ${colour.a})`,
      }
    },

    draw(time, canvas, ctx) {
      // move bubbles
      bubbles.forEach((bubble, index) => {
        bubbles[index] = this.moveBubble(bubble, canvas, time)
      })
      // clear the canvas
      ctx.clearRect(0, 0, canvas.width, canvas.height)
      // draw the bubbles
      bubbles.forEach((bubble) => {
        this.drawBubble(bubble, canvas, ctx)
      })
      // schedule next frame
      requestAnimationFrame((time) => this.draw(time, canvas, ctx))
    },

    moveBubble(bubble, canvas, time) {
      const progress = ((time - bubble.startTime) % bubble.duration) / bubble.duration
      return {
        ...bubble,
        x: progress,
        y: ((Math.sin(progress * bubble.arc) * bubble.amplitude) + bubble.offsetY),
      }
    },

    drawBubble(bubble, canvas, ctx) {
      canvas = this.$refs['bubbles']
      const vh = canvas.height / 100

      ctx.fillStyle = bubble.colour
      ctx.beginPath()
      ctx.ellipse(
        bubble.x * canvas.width,
        bubble.y * vh + (canvas.height / 2),
        bubble.diameter * vh,
        bubble.diameter * vh,
        0,
        0,
        2 * Math.PI
      )
      ctx.fill()
    },
  },
}
</script>


<style scoped lang="sass">
canvas
  position: absolute
  top: 0
  left: 0
  width: 100%
  height: 100vh
</style>
